import base64, subprocess, os

# Conteudo do bms_desktop.html corrigido (base64)
B64 = ""

# Decodifica e salva
content = base64.b64decode(B64)
with open("bms_desktop.html", "wb") as f:
    f.write(content)
print("Arquivo atualizado!")

# Git push automatico
subprocess.run(["git", "add", "bms_desktop.html"])
subprocess.run(["git", "commit", "-m", "BMS Desktop - caldeira com chama animada"])
result = subprocess.run(["git", "push"], capture_output=True, text=True)
print(result.stdout)
print("Deploy concluido!" if result.returncode == 0 else "Erro: " + result.stderr)
